use std::collections::BTreeMap;

fn count_colors(colors: &[String]) -> Result<BTreeMap<String, usize>, String> {
    if colors.len() > 2500 {
        return Err("Input size exceeds maximum limit of 2500 elements".to_string());
    }

    let mut color_counts = BTreeMap::new();

    for color in colors {
        let normalized_color = color.to_lowercase();
        *color_counts.entry(normalized_color).or_insert(0) += 1;
    }

