def fibonacci_sequence(n=1000):
    """Generate Fibonacci sequence dictionary using memoization"""
    # Initialize memo dictionary with base cases
    memo = {0: 0, 1: 1}

    def fib(num):
        """Recursive function with memoization"""
        if num in memo:
            return memo[num]
        memo[num] = fib(num-1) + fib(num-2)
        return memo[num]

    # Generate sequence and store in dictionary
    result = {}
    for i in range(n):
        if i < 0:
            raise ValueError("Input must be non-negative")
        result[i] = fib(i)

    return result

# Generate Fibonacci dictionary
