import (
	"fmt"
	"sync"
	"time"
)

func main() {
	messages := make(chan string, 200)
	var wg sync.WaitGroup

	// Message processor
	go func() {
		for msg := range messages {
			fmt.Println(msg)
		}
	}()

	// Send function that handles overflow
