class ReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;
    std::unordered_map<int, Reservation> reservations;

public:
    bool addAirline(const Airline& airline) {
        if (airlines.find(airline.getCode()) != airlines.end()) {
            return false;
        }
        airlines[airline.getCode()] = airline;
        return true;
    }

    Airline* getAirline(const std::string& airlineCode) {
        auto it = airlines.find(airlineCode);
        if (it != airlines.end()) {
            return &(it->second);
        }
        return nullptr;
    }

    int makeReservation(const std::string& passengerName, 
                        const std::string& airlineCode, 
                        const std::string& flightNumber) {
        // Check if airline exists
        Airline* airline = getAirline(airlineCode);
        if (!airline) {
            throw std::runtime_error("Airline not found");
        }

        // Check if flight exists
        Flight* flight = airline->getFlight(flightNumber);
        if (!flight) {
            throw std::runtime_error("Flight not found");
        }

        // Check if seats are available
        if (flight->getAvailableSeats() <= 0) {
            throw std::runtime_error("No available seats on this flight");
        }

        // Create reservation
        Reservation reservation(passengerName, airlineCode, flightNumber);
        int reservationId = reservation.getReservationId();

        // Add reservation to flight
        if (!flight->addReservation(reservationId)) {
            throw std::runtime_error("Failed to add reservation to flight");
        }

        // Store reservation
        reservations[reservationId] = reservation;
        return reservationId;
    }

    bool cancelReservation(int reservationId) {
        auto it = reservations.find(reservationId);
        if (it == reservations.end() || !it->second.getIsActive()) {
            return false;
        }

        Reservation& reservation = it->second;
        Airline* airline = getAirline(reservation.getAirlineCode());
        if (!airline) {
            return false;
        }

        Flight* flight = airline->getFlight(reservation.getFlightNumber());
        if (!flight) {
            return false;
        }

        if (flight->cancelReservation(reservationId)) {
            reservation.cancel();
            return true;
        }
        return false;
    }

    void displayReservation(int reservationId) const {
        auto it = reservations.find(reservationId);
        if (it != reservations.end()) {
            it->second.displayReservation();
        } else {
            std::cout << "Reservation not found\n";
        }
    }

    void displayAllAirlines() const {
        std::cout << "Available Airlines:\n";
        for (const auto& pair : airlines) {
            std::cout << pair.second.getName() << " (" << pair.second.getCode() << ")\n";
        }
    }
};

