        vector<vector<int>> dist(size, vector<int>(size, INT_MAX));
        // Parent tracking for path reconstruction
        vector<vector<pair<int, int>>> parent(size, vector<pair<int, int>>(size, {-1, -1}));

        // Min-heap priority queue for Dijkstra's algorithm
        priority_queue<pair<int, pair<int, int>>, vector<pair<int, pair<int, int>>>, greater<>> pq;

        // Unordered set with custom hash for tracking visited nodes
        unordered_set<pair<int, int>, PairHash> visited;

        // Directions: right, down, left, up
        const int dx[] = {0, 1, 0, -1};
        const int dy[] = {1, 0, -1, 0};

        // Initialize starting point
        dist[startX][startY] = grid[startX][startY];
        pq.push({dist[startX][startY], {startX, startY}});

        while (!pq.empty()) {
            auto [currDist, pos] = pq.top();
            pq.pop();

            int x = pos.first, y = pos.second;

            // Skip if already visited
            if (visited.find({x, y}) != visited.end()) continue;
            visited.insert({x, y});

            // Early termination if reached destination
            if (x == endX && y == endY) break;

            // Skip if current distance is outdated
            if (currDist > dist[x][y]) continue;

            // Explore all 4 directions
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];

                // Check bounds
                if (nx < 0 || nx >= size || ny < 0 || ny >= size) continue;

                // Skip if already visited
                if (visited.find({nx, ny}) != visited.end()) continue;

                int newDist = dist[x][y] + grid[nx][ny];

                // Update if better path found
                if (newDist < dist[nx][ny]) {
                    dist[nx][ny] = newDist;
                    parent[nx][ny] = {x, y};
                    pq.push({newDist, {nx, ny}});
                }
            }
        }

        // Reconstruct path
        vector<pair<int, int>> path;
        int cx = endX, cy = endY;

        // Check if destination was reached
        if (dist[endX][endY] == INT_MAX) {
            return path;  // Empty path, no solution
        }

        while (cx != -1 && cy != -1) {
            path.push_back({cx, cy});
            auto p = parent[cx][cy];
            cx = p.first;
            cy = p.second;
        }

        reverse(path.begin(), path.end());
        return path;
    }

    int getTotalCost(const vector<pair<int, int>>& path) {
        int cost = 0;
        for (const auto& pos : path) {
            cost += grid[pos.first][pos.second];
        }
        return cost;
    }

    void printPath(const vector<pair<int, int>>& path) {
        if (path.empty()) {
            cout << "No path found!" << endl;
            return;
        }

        cout << "Path: ";
        for (size_t i = 0; i < path.size(); i++) {
            cout << "(" << path[i].first << "," << path[i].second << ")";
            if (i < path.size() - 1) cout << " -> ";
        }
        cout << endl;
        cout << "Total cost: " << getTotalCost(path) << endl;
        cout << "Path length: " << path.size() << " intersections" << endl;
    }
};

