    public static long processTaskQueue(Queue<Task> taskQueue) {
        if (taskQueue == null || taskQueue.isEmpty()) {
            throw new IllegalArgumentException("Task queue cannot be empty");
        }

        PriorityQueue<Task> priorityQueue = new PriorityQueue<>(100, 
            (t1, t2) -> Integer.compare(t2.getPriority(), t1.getPriority()));

        priorityQueue.addAll(taskQueue);

        long startTime = System.currentTimeMillis();
        long totalDuration = 0;

        try {
            while (!priorityQueue.isEmpty()) {
                Task task = priorityQueue.poll();
                // Simulate task execution
                Thread.sleep(task.getDuration());
                totalDuration += task.getDuration();
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new RuntimeException("Task execution was interrupted", e);
        }

        long endTime = System.currentTimeMillis();
        return endTime - startTime;
    }

    public static class Task {
        private final int priority;
        private final long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }

