        for (const auto& product : sorted) {
            std::cout << std::left << std::setw(30) << product.getName() 
                     << "$" << std::setw(9) << std::fixed << std::setprecision(2) << product.getPrice() 
                     << std::setw(15) << product.getGenre() 
                     << std::setw(10) << product.getStock() << std::endl;
        }
    }

    // Display cart contents
    void displayCart() const {
        std::cout << "\nShopping Cart:\n";
        std::cout << std::left << std::setw(30) << "Product" 
                 << std::setw(10) << "Price" 
                 << std::setw(10) << "Quantity" 
                 << std::setw(15) << "Discount" 
                 << std::setw(10) << "Total" << std::endl;
        std::cout << std::string(75, '-') << std::endl;

        for (const auto& item : cart) {
            const Product& product = item.getProduct();
            std::cout << std::left << std::setw(30) << product.getName() 
                     << "$" << std::setw(9) << std::fixed << std::setprecision(2) << product.getPrice() 
                     << std::setw(10) << item.getQuantity() 
                     << std::setw(14) << product.getDiscountPercent() << "%" 
                     << "$" << std::fixed << std::setprecision(2) << item.getTotalPrice() << std::endl;
        }

        std::cout << std::string(75, '-') << std::endl;
