struct Reservation {
    int screenId;
    int row;
    int seat;
    std::string customerId;

    Reservation(int screenId, int row, int seat, const std::string& customerId)
        : screenId(screenId), row(row), seat(seat), customerId(customerId) {}

    bool operator<(const Reservation& other) const {
        if (screenId != other.screenId) return screenId < other.screenId;
        if (row != other.row) return row < other.row;
        if (seat != other.seat) return seat < other.seat;
        return customerId < other.customerId;
    }
};

class CinemaReservationSystem {
private:
    std::set<Reservation> reservations;
    const size_t MAX_RESERVATIONS = 10000;
    std::mutex reservationMutex;

public:
    bool isSeatAvailable(int screenId, int row, int seat) {
        std::lock_guard<std::mutex> lock(reservationMutex);
        for (const auto& res : reservations) {
            if (res.screenId == screenId && res.row == row && res.seat == seat) {
                return false;
            }
        }
        return true;
    }

    void makeReservation(int screenId, int row, int seat, const std::string& customerId) {
        std::lock_guard<std::mutex> lock(reservationMutex);

        if (reservations.size() >= MAX_RESERVATIONS) {
            throw std::runtime_error("Reservation system at maximum capacity");
        }

        // Check if seat is already reserved
        for (const auto& res : reservations) {
            if (res.screenId == screenId && res.row == row && res.seat == seat) {
                throw std::runtime_error("Seat already reserved");
            }
        }

        reservations.emplace(screenId, row, seat, customerId);
    }

    bool cancelReservation(int screenId, int row, int seat, const std::string& customerId) {
        std::lock_guard<std::mutex> lock(reservationMutex);
        Reservation toCancel(screenId, row, seat, customerId);
        return reservations.erase(toCancel) > 0;
    }

    size_t getReservationCount() const {
        std::lock_guard<std::mutex> lock(reservationMutex);
        return reservations.size();
    }
};

void processReservation(CinemaReservationSystem& system, int screenId, 
                        int row, int seat, const std::string& customerId) {
    try {
        if (system.isSeatAvailable(screenId, row, seat)) {
            system.makeReservation(screenId, row, seat, customerId);
            std::cout << "Seat " << row << "-" << seat << " reserved for " << customerId << std::endl;
        } else {
            std::cout << "Seat " << row << "-" << seat << " is not available" << std::endl;
        }
    } catch (const std::exception& e) {
        std::cout << "Error: " << e.what() << std::endl;
    }
}

int main() {
    CinemaReservationSystem cinema;

    std::vector<std::thread> threads;

    threads.push_back(std::thread(processReservation, std::ref(cinema), 1, 5, 10, "Customer1"));
    threads.push_back(std::thread(processReservation, std::ref(cinema), 1, 5, 10, "Customer2"));
    threads.push_back(std::thread(processReservation, std::ref(cinema), 1, 6, 12, "Customer3"));

    for (auto& t : threads) {
        t.join();
    }

    if (cinema.cancelReservation(1, 6, 12, "Customer3")) {
        std::cout << "Reservation for Customer3 canceled successfully" << std::endl;
    } else {
        std::cout << "Failed to cancel reservation" << std::endl;
    }

    std::cout << "Total reservations: " << cinema.getReservationCount() << std::endl;

    return 0;
}

