use smallvec::{smallvec, SmallVec};
use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq)]
struct Task {
    id: u64,
    priority: u32,
    description: String,
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        other.priority.cmp(&self.priority)
    }
}

impl PartialOrd for Task {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Eq for Task {}

#[derive(Debug)]
enum TaskError {
    QueueFull,
    NotFound,
}

struct PriorityQueue {
    tasks: SmallVec<[Task; 8]>,
    capacity: usize,
}

impl PriorityQueue {
    fn new() -> Self {
        Self { 
            tasks: SmallVec::new(),
            capacity: 200,
        }
    }

    fn add(&mut self, task: Task) -> Result<(), TaskError> {
        if self.tasks.len() >= self.capacity {
            return Err(TaskError::QueueFull);
        }

        let pos = self.tasks.binary_search(&task).unwrap_or_else(|e| e);
        self.tasks.insert(pos, task);
        Ok(())
    }

    fn update_priority(&mut self, id: u64, new_priority: u32) -> Result<(), TaskError> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            let mut task = self.tasks.remove(pos);
            task.priority = new_priority;
            let new_pos = self.tasks.binary_search(&task).unwrap_or_else(|e| e);
            self.tasks.insert(new_pos, task);
            Ok(())
        } else {
            Err(TaskError::NotFound)
        }
    }

    fn remove(&mut self, id: u64) -> Result<Task, TaskError> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            Ok(self.tasks.remove(pos))
        } else {
            Err(TaskError::NotFound)
        }
    }

    fn peek(&self) -> Option<&Task> {
        self.tasks.first()
    }

    fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() { None } else { Some(self.tasks.remove(0)) }
    }

    fn len(&self) -> usize {
        self.tasks.len()
    }

    fn is_empty(&self) -> bool {
        self.tasks.is_empty()
    }
}
