int longestConsecutive(vector<int>& nums) {
    if (nums.empty()) return 0;

    // Use unordered_map as a hash map to store elements with their status
    unordered_map<int, bool> numMap;

    // Add elements to the map while ensuring size constraint
    for (int num : nums) {
        if (numMap.size() < 1000) {
            numMap[num] = true;
        } else {
            break;  // Stop adding if we reach size constraint
        }
    }

    int longestStreak = 0;

    for (auto& pair : numMap) {
        int num = pair.first;
        // Only start counting sequences at the beginning of a sequence
        if (numMap.find(num - 1) == numMap.end()) {
            int currentNum = num;
            int currentStreak = 1;

            // Count consecutive elements
            while (numMap.find(currentNum + 1) != numMap.end()) {
                currentNum++;
                currentStreak++;
            }

            longestStreak = max(longestStreak, currentStreak);
        }
    }

    return longestStreak;
}

