public class StockProfit {
    private static final int MAX_SIZE = 2000;

    public static void main(String[] args) {
        ArrayList<Double> prices = new ArrayList<>(MAX_SIZE);

        // Example with sample data
        double[] samplePrices = {7.0, 1.0, 5.0, 3.0, 6.0, 4.0, 2.0, 8.0};
        for (double price : samplePrices) {
            prices.add(price);
        }

        double maxProfit = findMaxProfit(prices);
        System.out.println("Maximum possible profit: " + maxProfit);

        // Test with larger dataset
        testWithLargeDataset();
    }

    public static double findMaxProfit(ArrayList<Double> prices) {
        if (prices == null || prices.size() < 2 || prices.size() > MAX_SIZE) {
            return 0.0;
        }

        double minPrice = prices.get(0);
        double maxProfit = 0.0;

        for (int i = 1; i < prices.size(); i++) {
            double currentPrice = prices.get(i);
            maxProfit = Math.max(maxProfit, currentPrice - minPrice);
            minPrice = Math.min(minPrice, currentPrice);
        }

        return maxProfit;
    }

    private static void testWithLargeDataset() {
        ArrayList<Double> largePrices = new ArrayList<>(MAX_SIZE);

        // Generate test data up to 2000 elements
        for (int i = 0; i < MAX_SIZE; i++) {
            largePrices.add(Math.random() * 100 + 1);
        }

